#include <bits/stdc++.h>
using namespace std;
map<string,int> t,use,last;
struct Node{
    string mac;
    int m,cnt;
}ip[100005];
bool cmp(Node x,Node y){
    return x.m<y.m;
}
int n,k,ans,siz;
queue<Node> q;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    cin>>n>>k;
    for(int i=1;i<=n;i++){
        string tmp;
        cin>>ip[i].mac>>tmp;
        ip[i].m=((tmp[0]-'0')*10+tmp[1]-'0')*60+(tmp[3]-'0')*10+tmp[4]-'0';
    }
    sort(ip+1,ip+n+1,cmp);
    for(int i=1;i<=n;i++){
        while(q.size() && (t[q.front().mac]+k<=ip[i].m || q.front().cnt!=last[q.front().mac]))
            siz-=(q.front().cnt==last[q.front().mac]),use[q.front().mac]=(t[q.front().mac]+k>ip[i].m),q.pop();
    	t[ip[i].mac]=ip[i].m;
    	ip[i].cnt=i;
    	if(!use[ip[i].mac])
    		siz++,use[ip[i].mac]=1;
		q.push(ip[i]),last[ip[i].mac]=i;
        ans=max(ans,siz);
    }
    cout<<ans;
    return 0;
}
